import React from "react";
import "./pricing.css";

const chooselist = [
  {
    heading: "Platform + People",
    paragraph:
      "Not just dashboards - you get expert engineers implementing optimizations",
  },
  {
    heading: "Proven Results",
    paragraph: "Average 25-35% cost reduction with 3-6 month ROI",
  },
  {
    heading: "Predictable Pricing",
    paragraph:
      "No percentage of cloud spend - just transparent monthly fees",
  },
  {
    heading: "Fast ROI",
    paragraph: "Most clients see 3-6 month payback period",
  },
  {
    heading: "FinOps Certified",
    paragraph:
      "FinOps Foundation partners with certified professionals",
  },
  {
    heading: "No Lock-in",
    paragraph:
      "Month-to-month after initial term, own your optimizations",
  },
];

const Pricing = () => {
  return (
    <div className="pricing-page">
      {/* Hero Section */}
      <div className="container">
        <h3>C3Ops Pricing Plans</h3>

        <h4>
          FinOps-Driven DevOps Platform
          <br />
          + Expert Engineers
        </h4>

        <h6>
          Choose the plan that matches your organization's cloud spend and
          optimization needs
        </h6>
      </div>

      {/* Green Highlight Section */}
      <div className="card-container">
        <h3>What Makes C3Ops Different</h3>

        <div className="benefits">
          <div>
            <ul>
              <li>
                Enterprise-grade FinOps platform (CMDB, Budget Tracking,
                Cost Dashboards)
              </li>

              <li>
                Hands-on implementation, not just recommendations
              </li>
            </ul>
          </div>

          <div>
            <ul>
              <li>
                Dedicated FinOps Certified Engineer working with your team
              </li>

              <li>
                Proven 3-phase approach:
                Assess → Optimize → Govern
              </li>
            </ul>
          </div>
        </div>
      </div>

      {/* Why Choose Cards */}
      <div className="card-section">
        {chooselist.map((item, index) => (
          <div className="choose-card" key={index}>
            <div className="icon">✓</div>

            <h4>{item.heading}</h4>

            <p>{item.paragraph}</p>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Pricing;
